Booleans and Conditions
score = 98

if score == 100:
    print("Top marks!")
elif score &gt; 90 and score &lt; 100:
    print("High score!")
elif score &gt; 10 and score &lt;= 90:
    pass
else:
    print("Better luck next time.")

